import React, { useState, useRef, useMemo, useEffect, useCallback } from "react";
import { motion } from "framer-motion";
import { ChevronLeft, ChevronRight } from "lucide-react";
import "./Products.css";

const Products = () => {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const scrollRef = useRef(null);
  const [showForm, setShowForm] = useState(false);
  const [showDetails, setShowDetails] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [selectedForDetails, setSelectedForDetails] = useState(null);

  useEffect(() => {
    fetch('http://localhost:8080/indiaadvertising/api/getData.php')
      .then(res => {
        if (!res.ok) {
          throw new Error(`HTTP error! status: ${res.status}`);
        }
        return res.json();
      })
      .then(fetchedData => {
        console.log('Fetched Data:', fetchedData);
        setData(fetchedData);
      })
      .catch(err => {
        console.error('Fetch error:', err);
        alert('Failed to load products: ' + err.message + '. Check console for details.');
      })
      .finally(() => setLoading(false));
  }, []);

  // Filter out any null subProducts (defense in depth) - always compute
  const categories = useMemo(() => 
    data?.categories?.map(cat => ({
      ...cat,
      subProducts: (cat.subProducts || []).filter(prod => prod != null)
    })) || [], [data]
  );

  const { description = "" } = data?.companyInfo || {};
  const products = useMemo(() => categories, [categories]);

  // Helper to get full image URL - always compute
  const getImageUrl = useCallback((img) => {
    if (img?.startsWith('http')) {
      return img; // External URL
    }
    return `http://localhost:8080/indiaadvertising/public/${img}`; // Local upload
  }, []);

  // Scroll buttons
  const scroll = useCallback((direction) => {
    if (scrollRef.current) {
      const scrollAmount = 300;
      scrollRef.current.scrollBy({
        left: direction === "left" ? -scrollAmount : scrollAmount,
        behavior: "smooth",
      });
    }
  }, []);

  // Filter logic for search (only for category buttons)
  const filteredProducts = useMemo(() => 
    products.filter((p) =>
      p.category?.toLowerCase().includes(searchTerm.toLowerCase())
    ), [products, searchTerm]
  );

  // Unique categories from filtered products
  const categoriesList = useMemo(() => 
    [...new Set(filteredProducts.map(p => p.category))], [filteredProducts]
  );

  // Featured categories (first 4 when no active)
  const featuredCategories = useMemo(() => 
    categoriesList, [categoriesList]
  );

  // Sub products for active category
  const activeSubProducts = useMemo(() => {
    if (!activeCategory) return [];
    return products.find((p) => p.category === activeCategory)?.subProducts || [];
  }, [products, activeCategory]);

  // When user clicks "Get Quote"
  const handleQuote = useCallback((product) => {
    setSelectedProduct(product);
    setShowForm(true);
  }, []);

  // When user clicks "Product Details"
  const handleDetails = useCallback((product) => {
    setSelectedForDetails(product);
    setShowDetails(true);
  }, []);

  // For custom solution enquiry
  const handleCustomQuote = useCallback(() => {
    setSelectedProduct({ name: "Custom Solution" });
    setShowForm(true);
  }, []);

  // Early returns after all hooks
  if (loading) return <div className="py-12 text-center">Loading products...</div>;
  if (!data || data.error) return <div className="py-12 text-center">No data available. {data?.error && `Error: ${data.error}`}</div>;

  return (
    <section id="products" className="py-12 text-gray-800 sm:py-20 bg-gray-50">
      <div className="px-4 mx-auto max-w-7xl">
        <motion.h2
          className="mb-6 text-3xl font-bold text-center text-blue-700 sm:text-5xl sm:mb-10"
          initial={{ y: -50 }}
          whileInView={{ y: 0 }}
          viewport={{ once: true }}
        >
          Our Products & Services
        </motion.h2>

        <p className="max-w-3xl mx-auto mb-8 text-lg text-center text-gray-600">
          {description}
        </p>

        {/* Categories Scroll (Our Range) */}
        <div className="relative mb-10" role="navigation" aria-label="Product categories">
          <button
            onClick={() => scroll("left")}
            className="absolute left-0 top-1/2 -translate-y-1/2 text-blue-600 scroll-arrow p-2 hover:bg-blue-100 rounded-full"
            aria-label="Scroll left"
          >
            <ChevronLeft size={24} />
          </button>

          <div
            ref={scrollRef}
            className="flex gap-3 px-10 overflow-x-auto products-scroll no-scrollbar"
            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
          >
            <motion.button
              onClick={() => {
                setActiveCategory(null);
              }}
              className={`px-6 py-3 rounded-full font-semibold transition flex-shrink-0 ${
                !activeCategory
                  ? "bg-blue-600 text-white"
                  : "bg-white text-blue-700 border border-blue-300"
              }`}
              whileHover={{ scale: 1.05 }}
              aria-pressed={!activeCategory}
            >
              All Categories
            </motion.button>

            {categoriesList.map((category, index) => (
              <motion.button
                key={index}
                onClick={() => {
                  setActiveCategory(category);
                }}
                className={`px-6 py-3 rounded-full font-semibold transition flex-shrink-0 ${
                  activeCategory === category
                    ? "bg-blue-600 text-white"
                    : "bg-white text-blue-700 border border-blue-300"
                }`}
                whileHover={{ scale: 1.05 }}
                aria-pressed={activeCategory === category}
              >
                {category}
              </motion.button>
            ))}
          </div>

          <button
            onClick={() => scroll("right")}
            className="absolute right-0 top-1/2 -translate-y-1/2 text-blue-600 scroll-arrow p-2 hover:bg-blue-100 rounded-full"
            aria-label="Scroll right"
          >
            <ChevronRight size={24} />
          </button>
        </div>

        {/* Featured Categories or Sub Products */}
        <motion.div
          className="grid gap-6 lg:grid-cols-4"
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          transition={{ staggerChildren: 0.1 }}
          viewport={{ once: true }}
        >
          {!activeCategory ? (
            // Featured Categories View
            featuredCategories.length === 0 ? (
              <div className="col-span-full text-center py-8" role="alert" aria-live="polite">
                <p className="text-gray-500">No categories found.</p>
              </div>
            ) : (
              featuredCategories.slice(0, 12).map((category) => {
                const catData = products.find((p) => p.category === category);
                const subProducts = catData?.subProducts || [];
                const firstImage = subProducts[0]?.images?.[0];
                return (
                  <FeaturedCategoryCard
                    key={category}
                    category={category}
                    subProducts={subProducts}
                    imageSrc={firstImage ? getImageUrl(firstImage) : null}
                    onViewAll={() => setActiveCategory(category)}
                  />
                );
              })
            )
          ) : (
            // Sub Products Grid View
            activeSubProducts.length === 0 ? (
              <div className="col-span-full text-center py-8" role="alert" aria-live="polite">
                <p className="text-gray-500">No products found.</p>
              </div>
            ) : (
              <div className="lg:col-span-full lg:grid lg:grid-cols-3 lg:gap-6">
                {activeSubProducts.map((sub, idx) => (
                  <ProductCard
                    key={idx}
                    name={sub.name}
                    price={sub.price}
                    images={sub.images || []}
                    description={sub.description}
                    specs={sub.specs || []}
                    additionalInfo={sub.additionalInfo || {}}
                    onQuote={() => handleQuote(sub)}
                    onDetails={() => handleDetails(sub)}
                    getImageUrl={getImageUrl}
                  />
                ))}
              </div>
            )
          )}
        </motion.div>

        <div className="mt-12 text-center">
          <button
            onClick={handleCustomQuote}
            className="inline-block px-8 py-4 text-lg font-semibold text-white transition-colors bg-blue-600 rounded-full hover:bg-blue-700 focus:ring-2 focus:ring-blue-300"
            aria-label="Enquire for custom solutions"
          >
            Enquire for Custom Solutions
          </button>
        </div>
      </div>

      {/* Quote Modal */}
      {showForm && (
        <QuoteForm
          product={selectedProduct}
          onClose={() => setShowForm(false)}
        />
      )}

      {/* Product Details Modal */}
      {showDetails && (
        <ProductDetails
          product={selectedForDetails}
          onClose={() => setShowDetails(false)}
          getImageUrl={getImageUrl}
        />
      )}
    </section>
  );
};

// Featured Category Card
const FeaturedCategoryCard = React.memo(({ category, subProducts, imageSrc, onViewAll }) => (
  <motion.div
    className="flex flex-col bg-white border border-gray-200 shadow-lg rounded-xl"
    whileHover={{ y: -5 }}
    role="article"
    aria-labelledby={`${category.replace(/\s+/g, '-').toLowerCase()}-title`}
  >
    <div className="relative h-48 mb-4 overflow-hidden rounded-t-xl flex-shrink-0">
      {imageSrc ? (
        <img 
          src={imageSrc} 
          alt={`${category} example`} 
          className="object-cover w-full h-full" 
          loading="lazy"
          onError={(e) => { e.target.style.display = 'none'; }}
        />
      ) : (
        <div className="flex items-center justify-center w-full h-full bg-gray-100 rounded-t-xl">
          <span className="text-gray-500">Category Preview</span>
        </div>
      )}
    </div>

    <div className="p-6 flex flex-col flex-grow">
      <h3 id={`${category.replace(/\s+/g, '-').toLowerCase()}-title`} className="mb-4 text-xl font-bold text-gray-900">{category}</h3>
      
      {subProducts.length > 0 && (
        <ul className="mb-4 space-y-2 text-sm text-gray-600 flex-grow" role="list">
          {subProducts.slice(0, 4).map((sub, idx) => (
            <li key={idx} className="flex items-center">
              • {sub.name}
            </li>
          ))}
          {subProducts.length > 4 && (
            <li className="text-gray-400">...and more</li>
          )}
        </ul>
      )}

      <button
        onClick={onViewAll}
        className="self-start px-4 py-2 text-blue-600 font-medium transition-colors border border-blue-300 rounded hover:bg-blue-50 focus:ring-2 focus:ring-blue-300"
        aria-label={`View all in ${category}`}
      >
        + View All
      </button>
    </div>
  </motion.div>
));

FeaturedCategoryCard.displayName = 'FeaturedCategoryCard';

// Product Card
const ProductCard = React.memo(({ name, price, images = [], description, specs = [], additionalInfo = {}, onQuote, onDetails, getImageUrl }) => (
  <motion.div
    className="flex flex-col p-6 transition-shadow bg-white border border-gray-200 shadow-lg rounded-xl hover:shadow-xl"
    whileHover={{ y: -5 }}
    role="article"
    aria-labelledby={`${name.replace(/\s+/g, '-').toLowerCase()}-title`}
  >
    <div className="relative h-48 mb-4 overflow-hidden rounded-lg flex-shrink-0">
      {images?.[0] ? (
        <>
          <img 
            src={getImageUrl(images[0])} 
            alt={`${name} preview`} 
            className="object-cover w-full h-full" 
            loading="lazy"
            onError={(e) => { e.target.style.display = 'none'; }}
          />
          {images.length > 1 && (
            <div className="absolute top-2 right-2 bg-blue-600 text-white px-2 py-1 rounded-full text-xs">
              +{images.length - 1}
            </div>
          )}
        </>
      ) : (
        <div className="flex items-center justify-center w-full h-full bg-gray-100 rounded">
          <span className="text-gray-500">Product Preview</span>
        </div>
      )}
    </div>

    <h3 id={`${name.replace(/\s+/g, '-').toLowerCase()}-title`} className="mb-2 text-xl font-bold text-gray-900 flex-shrink-0">{name}</h3>
    
    {price && (
      <p className="mb-2 text-lg font-semibold text-green-600 flex-shrink-0">{price}</p>
    )}

    {description && (
      <p className="mb-4 text-sm text-gray-600 line-clamp-2 flex-shrink-0">
        {description}
      </p>
    )}

    {(specs.length > 0 || Object.keys(additionalInfo).length > 0) && (
      <div className="mb-4 text-xs text-gray-500 flex-shrink-0 space-y-1">
        {specs.slice(0, 2).map((spec, i) => (
          <p key={i} className="mb-1"><strong>{spec.key}:</strong> {spec.value}</p>
        ))}
        {Object.entries(additionalInfo).slice(0, 1).map(([key, value]) => (
          <p key={key}><strong>{key}:</strong> {value}</p>
        ))}
      </div>
    )}

    <div className="flex space-x-2 mt-auto">
      <button
        onClick={onQuote}
        className="flex-1 px-4 py-2 text-white transition-colors bg-blue-600 rounded hover:bg-blue-700 focus:ring-2 focus:ring-blue-300"
        aria-label={`Get quote for ${name}`}
      >
        Get Quote
      </button>
      <button
        onClick={onDetails}
        className="flex-1 px-4 py-2 text-gray-700 transition-colors bg-gray-200 rounded hover:bg-gray-300 focus:ring-2 focus:ring-gray-300"
        aria-label={`View details for ${name}`}
      >
        Product Details
      </button>
    </div>
  </motion.div>
));

ProductCard.displayName = 'ProductCard';

// Product Details Modal
const ProductDetails = ({ product, onClose, getImageUrl }) => {
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  if (!product) return null;

  const totalImages = product.images?.length || 1;
  const nextImage = () => setCurrentImageIndex((prev) => (prev + 1) % totalImages);
  const prevImage = () => setCurrentImageIndex((prev) => (prev - 1 + totalImages) % totalImages);
  const goToImage = (index) => setCurrentImageIndex(index);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" role="dialog" aria-modal="true" aria-labelledby="details-title">
      <motion.div
        className="relative w-full max-w-2xl p-6 bg-white shadow-lg rounded-xl max-h-[90vh] overflow-y-auto"
        initial={{ scale: 0.95, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        exit={{ scale: 0.95, opacity: 0 }}
      >
        <button 
          onClick={onClose} 
          className="absolute text-gray-500 top-3 right-3 hover:text-gray-800 focus:ring-2 focus:ring-gray-300"
          aria-label="Close details"
        >
          ✕
        </button>
        <h3 id="details-title" className="mb-4 text-2xl font-bold text-blue-700">{product.name}</h3>
        
        {product.price && (
          <p className="mb-4 text-lg font-semibold text-green-600">Price: {product.price}</p>
        )}
        
        <div className="mb-4 relative">
          <div className="relative h-64 overflow-hidden rounded-lg">
            {product.images?.length > 0 ? (
              <motion.img 
                key={currentImageIndex}
                src={getImageUrl(product.images[currentImageIndex])} 
                alt={`${product.name} image ${currentImageIndex + 1}`} 
                className="object-cover w-full h-full" 
                initial={{ x: 50 }}
                animate={{ x: 0 }}
                transition={{ duration: 0.3 }}
                loading="lazy"
                onError={(e) => { e.target.style.display = 'none'; }}
              />
            ) : (
              <div className="flex items-center justify-center w-full h-64 bg-gray-100 rounded-lg">
                <span className="text-gray-500">Product Preview</span>
              </div>
            )}
            {totalImages > 1 && (
              <>
                <button
                  onClick={prevImage}
                  className="absolute left-2 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full shadow-md"
                  aria-label="Previous image"
                >
                  <ChevronLeft size={20} />
                </button>
                <button
                  onClick={nextImage}
                  className="absolute right-2 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white p-2 rounded-full shadow-md"
                  aria-label="Next image"
                >
                  <ChevronRight size={20} />
                </button>
                <div className="absolute bottom-2 left-1/2 -translate-x-1/2 flex space-x-2">
                  {product.images?.map((_, index) => (
                    <button
                      key={index}
                      onClick={() => goToImage(index)}
                      className={`w-2 h-2 rounded-full ${index === currentImageIndex ? 'bg-blue-600' : 'bg-gray-300'}`}
                      aria-label={`Go to image ${index + 1}`}
                    />
                  ))}
                </div>
              </>
            )}
          </div>
          {totalImages > 1 && (
            <p className="text-center text-sm text-gray-500 mt-2">
              {currentImageIndex + 1} / {totalImages}
            </p>
          )}
        </div>

        {product.description && (
          <div className="mb-4">
            <h4 className="mb-2 font-medium text-gray-700">Description:</h4>
            <p className="text-gray-600">{product.description}</p>
          </div>
        )}
        
        {product.specs?.length > 0 && (
          <div className="mb-4">
            <h4 className="mb-2 font-medium text-gray-700">Key Specs:</h4>
            <ul className="space-y-1 text-sm text-gray-500" role="list">
              {product.specs.map((spec, idx) => (
                <li key={idx} className="flex">
                  <strong className="mr-2">{spec.key}:</strong> {spec.value}
                </li>
              ))}
            </ul>
          </div>
        )}

        {Object.keys(product.additionalInfo || {}).length > 0 && (
          <div className="mb-4">
            <h4 className="mb-2 font-medium text-gray-700">Additional Info:</h4>
            <ul className="space-y-1 text-sm text-gray-500" role="list">
              {Object.entries(product.additionalInfo).map(([key, value]) => (
                <li key={key} className="flex">
                  <strong className="mr-2">{key}:</strong> {value}
                </li>
              ))}
            </ul>
          </div>
        )}
      </motion.div>
    </div>
  );
};

// Quote Form Modal
const QuoteForm = ({ product, onClose }) => {
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    details: "",
  });
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');
    try {
      const response = await fetch('http://localhost:8080/indiaadvertising/sendQuoteMail.php', {
        method: "POST",
        body: new URLSearchParams({
          product: product?.name,
          name: form.name,
          email: form.email,
          phone: form.phone,
          details: form.details,
        }),
      });

      if (!response.ok) {
        throw new Error('Submission failed. Please try again.');
      }

      alert("✅ Quote request sent successfully!");
      onClose();
    } catch (err) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleChange = useCallback((field) => (e) => {
    setForm({ ...form, [field]: e.target.value });
  }, [form]);

  if (!product) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" role="dialog" aria-modal="true" aria-labelledby="quote-title">
      <motion.div
        className="relative w-full max-w-md p-6 bg-white shadow-lg rounded-xl"
        initial={{ scale: 0.95, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        exit={{ scale: 0.95, opacity: 0 }}
      >
        <button 
          onClick={onClose} 
          className="absolute text-gray-500 top-3 right-3 hover:text-gray-800 focus:ring-2 focus:ring-gray-300"
          aria-label="Close quote form"
        >
          ✕
        </button>
        <h3 id="quote-title" className="mb-4 text-2xl font-bold text-blue-700">
          Get Quote for {product.name}
        </h3>
        <form onSubmit={handleSubmit} className="space-y-4">
          <input
            type="text"
            placeholder="Your Name"
            value={form.name}
            onChange={handleChange('name')}
            required
            className="w-full px-4 py-2 border border-gray-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-300"
            aria-label="Your name"
          />
          <input
            type="email"
            placeholder="Your Email"
            value={form.email}
            onChange={handleChange('email')}
            required
            className="w-full px-4 py-2 border border-gray-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-300"
            aria-label="Your email"
          />
          <input
            type="tel"
            placeholder="Mobile Number"
            value={form.phone}
            onChange={handleChange('phone')}
            required
            className="w-full px-4 py-2 border border-gray-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-300"
            aria-label="Mobile number"
          />
          <textarea
            placeholder="Work Details"
            value={form.details}
            onChange={handleChange('details')}
            rows={3}
            className="w-full px-4 py-2 border border-gray-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-300"
            aria-label="Work details"
          />
          {error && <p className="text-red-500 text-sm">{error}</p>}
          <button
            type="submit"
            disabled={isLoading}
            className="w-full py-2 text-white transition-colors bg-blue-600 rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed focus:ring-2 focus:ring-blue-300"
            aria-label="Submit quote request"
          >
            {isLoading ? 'Sending...' : 'Submit Request'}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

export default Products;
